const ANTHROPIC_API_KEY = 'ANTHROPIC_API_KEY_FROM_ENV';
const item = $input.first().json;
const CC_CATEGORIES = [
  { id: 1, slug: 'politics', name: 'Politics' },
  { id: 2, slug: 'society', name: 'Society' },
  { id: 3, slug: 'sportsnews', name: 'Sports' },
  { id: 4, slug: 'southern-cameroons', name: 'S. Cameroons' },
  { id: 5, slug: 'business', name: 'Business' },
  { id: 6, slug: 'health', name: 'Health' },
  { id: 7, slug: 'headlines', name: 'Headlines' },
  { id: 8, slug: 'inside-cpdm', name: 'Biya' }
];
const rawBody = (item.raw_body || '').substring(0, 3000);
const systemPrompt = 'You are a senior journalist and editor at Cameroon Concord, an independent English-language digital news platform covering Cameroon and Central Africa since 2014. Your editorial voice is factual, authoritative, and accessible. You write like Reuters Africa — no sensationalism, no tribal framing, no editorializing. You always write in English regardless of source language.';
const categoryList = CC_CATEGORIES.map(c => c.slug + ' (id:' + c.id + ')').join(', ');
const userPrompt = 'You are given a raw news item scraped from a news source. Your job is to:\n1. Evaluate if this article is relevant to Cameroon, Chad, Central African Republic, Congo, Gabon, or Nigeria\n2. If relevant, rewrite it as a complete professional news article for Cameroon Concord\n3. Translate to English if the source is in French or another language\n4. Write in Cameroon Concord journalistic style — NOT a direct translation, a full rewrite\n5. Assign the correct category\n\nRAW TITLE: ' + item.raw_title + '\nRAW BODY: ' + rawBody + '\nSOURCE: ' + item.source_name + '\nSOURCE LANGUAGE: ' + item.language + '\n\nAvailable categories: ' + categoryList + '\n\nIf relevant and publishable, respond ONLY with valid JSON (no markdown fences):\n{\n  "publish": true,\n  "title": "Clean journalistic English headline max 80 chars",\n  "slug": "url-slug-lowercase-hyphens",\n  "excerpt": "2-3 sentence summary max 200 chars",\n  "body": "<p>Full article HTML using only p h2 h3 ul li tags. Min 4 paragraphs. Reuters-style English.</p>",\n  "category_id": 1,\n  "category_slug": "politics",\n  "meta_title": "SEO title max 60 chars",\n  "meta_desc": "SEO description max 155 chars",\n  "reject_reason": null\n}\n\nIf NOT relevant:\n{\n  "publish": false,\n  "reject_reason": "Brief reason"\n}';
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2000,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
});
return [{
  json: {
    api_key: ANTHROPIC_API_KEY,
    request_body: requestBody,
    ingested_id: item.id,
    raw_image_url: item.raw_image_url,
    source_url: item.source_url,
    source_name: item.source_name,
    raw_title: item.raw_title
  }
}];

const claudeResponse = $input.first().json;
const promptData = $('Build Claude Prompt').all()[$itemIndex].json;
const content = claudeResponse.content && claudeResponse.content[0] ? claudeResponse.content[0].text : '';
let parsed;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  const match = clean.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON in response');
  parsed = JSON.parse(match[0]);
} catch (e) {
  parsed = { publish: false, reject_reason: 'Parse error: ' + e.message };
}
return [{ json: { ...parsed, ingested_id: promptData.ingested_id, raw_image_url: promptData.raw_image_url, source_url: promptData.source_url, source_name: promptData.source_name } }];

const CC_API_KEY = 'AUTOMATION_KEY_REMOVED';
const CC_API_URL = 'https://www.cameroon-concord.com/api/admin/articles';
const item = $input.first().json;
const slug = (item.slug || (item.title || '').toLowerCase().replace(/[^a-z0-9\s-]/g,'').replace(/\s+/g,'-').substring(0,100));
const payload = {
  title: item.title,
  slug: slug,
  excerpt: item.excerpt || '',
  body: item.body || '',
  categoryId: item.category_id || 7,
  featuredImage: item.raw_image_url || '',
  status: 'draft',
  metaTitle: item.meta_title || (item.title || '').substring(0,60),
  metaDesc: item.meta_desc || item.excerpt || ''
};
return [{ json: { api_url: CC_API_URL, api_key: CC_API_KEY, payload_str: JSON.stringify(payload), ingested_id: item.ingested_id, title: item.title } }];

const response = $input.first().json;
const payload = $('Build CC Article Payload').all()[$itemIndex].json;
const success = !response.error && (response.id || response.article);
const articleId = response.id || (response.article && response.article.id) || null;
return [{ json: { success, article_id: articleId, ingested_id: payload.ingested_id, title: payload.title, error: response.error || null } }];
